/* 공지사항 조회수 증가 notice.updateNoticeViewCnt */
UPDATE TB_NOTICE
SET
    VIEW_CNT = VIEW_CNT + 1
WHERE NOTICE_ID = #{noticeId}

mapper.insert:
/* 공지사항 등록 notice.insertNotice */
INSERT INTO TB_NOTICE (
    NOTICE_ID
    , TITLE = #{title}
    , CONTENT = #{content}
    , PIN_YN = #{pinYn}
    , VIEW_CNT = #{viewCnt}
    , FEATURED_YN = #{featuredYn}
    , USE_YN = #{useYn}
    , CRTR_ID = #{crtrId}
    , CREATE_DT = NOW()
)

mapper.update:
/* 공지사항 수정 notice.updateNotice */
UPDATE TB_NOTICE
SET
    TITLE = #{title}
    , CONTENT = #{content}
    , PIN_YN = #{pinYn}
    , VIEW_CNT = #{viewCnt}
    , FEATURED_YN = #{featuredYn}
    , USE_YN = #{useYn}
    , MODIFY_DT = NOW()
WHERE NOTICE_ID = #{noticeId}

/* 공지사항 삭제 notice.deleteNotice */
UPDATE TB_NOTICE
SET
    USE_YN = 'N'
    , MODIFY_DT = NOW()
WHERE NOTICE_ID = #{noticeId}
